import { getItem } from '../../../../items/item.js';
import { toUserItem } from '../../../../items/user.js';
export const toServerItemLeaderboardRecord = (sonolus, localize, record) => ({
    name: record.name,
    rank: localize(record.rank),
    player: record.player,
    playerUser: record.playerUser
        ? toUserItem(sonolus, localize, getItem(sonolus.user.items, record.playerUser, `Record/${record.name}`, '.playerUser'))
        : undefined,
    value: localize(record.value),
});
